import AppKit

// RunCat cat sprite (5-frame gallop), embedded as base64 PNG so the binary is
// self-contained — no bundle/resource path lookup needed. Source art:
// Kyome22/menubar_runcat (Apache License 2.0); see THIRD_PARTY_LICENSE-RunCat.txt.
// Flagged as template images so macOS tints them to the menu bar (dark/light).
enum CatFrames {
    /// Decoded, template-flagged frames scaled to the given menu bar height.
    /// `flipped` mirrors the cat horizontally (RunCat's "flip direction").
    static func load(height: CGFloat, flipped: Bool = false) -> [NSImage] {
        let size = NSSize(width: (height * 56 / 36).rounded(), height: height)
        return base64.compactMap { b64 in
            guard let d = Data(base64Encoded: b64), let img = NSImage(data: d) else { return nil }
            img.size = size
            img.isTemplate = true
            return flipped ? mirror(img, size: size) : img
        }
    }

    private static func mirror(_ img: NSImage, size: NSSize) -> NSImage {
        let out = NSImage(size: size, flipped: false) { rect in
            let t = NSAffineTransform()
            t.translateX(by: rect.width, yBy: 0)
            t.scaleX(by: -1, yBy: 1)
            t.concat()
            img.draw(in: rect)
            return true
        }
        out.isTemplate = true
        return out
    }

    private static let base64: [String] = [
        "",
        "",
        "",
        "",
        "",
    ]
}
